// Estrai il Base64 audio
const base64Audio = $input.item.json.body.data.full_audio;
const conversationId = $input.item.json.body.data.conversation_id;

// Converti Base64 in Buffer binario
const audioBuffer = Buffer.from(base64Audio, 'base64');

return {
  json: {
    conversation_id: conversationId,
    agent_id: $input.item.json.body.data.agent_id,
    agent_name: $input.item.json.body.data.agent_name,
    user_id: $input.item.json.body.data.user_id
  },
  binary: {
    data: {
      data: audioBuffer.toString('base64'),
      mimeType: 'audio/mpeg',
      fileName: `conversation_${conversationId}.mp3`
    }
  }
};

const transcript = $json.transcript;

const fullText = transcript
  .filter(item => item.message) // esclude null
  .map(item => `${item.role}: ${item.message}`)
  .join('\n\n');

return [
  {
    json: {
      conversation_id: $json.conversation_id,
      agent_name: $json.agent_name,
      transcript_text: fullText
    }
  }
];

